    // SAVE JSON
    private void saveBorrowRecords() {
        try (BufferedWriter writer = new BufferedWriter(new FileWriter(FILE_NAME))) {
            writer.write("[\n");
            for (int i = 0; i < borrowRecords.size(); i++) {
                BorrowRecord record = borrowRecords.get(i);
                writer.write("  {\n");
                writer.write("    \"memberId\": \"" + escapeJson(record.getMemberId()) + "\",\n");
                writer.write("    \"memberName\": \"" + escapeJson(record.getMemberName()) + "\",\n");
                writer.write("    \"bookTitle\": \"" + escapeJson(record.getBookTitle()) + "\",\n");
                writer.write("    \"borrowDate\": \"" + record.getBorrowDate() + "\",\n");
                writer.write("    \"dueDate\": \"" + record.getDueDate() + "\",\n");
                writer.write("    \"returnDate\": \"" + (record.getReturnDate() != null ? record.getReturnDate() : "null") + "\"\n");
                writer.write("  }");
                if (i < borrowRecords.size() - 1) {
                    writer.write(",");
                }
                writer.newLine();
            }
            writer.write("]");
        } catch (IOException e) {
            System.out.println("Error saving borrow records: " + e.getMessage());
        }
    }

    // LOAD JSON (SIMPLIFIED)
    private void loadBorrowRecords() {
        ensureJsonFileExists();
        borrowRecords = new ArrayList<>();

        try (BufferedReader reader = new BufferedReader(new FileReader(FILE_NAME))) {
            StringBuilder content = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) {
                content.append(line.trim());
            }

            String json = content.toString();
            if (json.length() <= 2) return; // Empty array []

            // Remove outer brackets and split by objects
            String[] objects = json.substring(1, json.length() - 1).split("\\},\\s*\\{");

            for (String obj : objects) {
                obj = obj.replace("{", "").replace("}", "").trim();
                if (obj.isEmpty()) continue;

                // Parse key-value pairs
                String[] pairs = obj.split(",\\s*");
                String memberId = null, memberName = null, bookTitle = null;
                String borrowDateStr = null, dueDateStr = null, returnDateStr = null;

                for (String pair : pairs) {
                    String[] keyValue = pair.split(":\\s*", 2);
                    if (keyValue.length != 2) continue;

                    String key = keyValue[0].replace("\"", "");
                    String value = keyValue[1].replace("\"", "");

                    switch (key) {
                        case "memberId" -> memberId = value;
                        case "memberName" -> memberName = value;
                        case "bookTitle" -> bookTitle = value;
                        case "borrowDate" -> borrowDateStr = value;
                        case "dueDate" -> dueDateStr = value;
                        case "returnDate" -> returnDateStr = value;
                    }
                }

                // Validate required fields
                if (memberId == null || bookTitle == null || borrowDateStr == null || dueDateStr == null) {
                    continue;
                }

                if (memberName == null) memberName = "";

                try {
                    LocalDate borrowDate = LocalDate.parse(borrowDateStr);
                    LocalDate dueDate = LocalDate.parse(dueDateStr);
                    LocalDate returnDate = null;

                    if (returnDateStr != null && !returnDateStr.equals("null")) {
                        returnDate = LocalDate.parse(returnDateStr);
                    }

                    BorrowRecord record = new BorrowRecord(memberId, memberName, bookTitle, borrowDate, dueDate);
                    if (returnDate != null) {
                        record.setReturnDate(returnDate);
                    }
                    borrowRecords.add(record);
                } catch (Exception e) {
                    System.out.println("Error parsing borrow record: " + e.getMessage());
                }
            }
        } catch (IOException e) {
            System.out.println("Error loading borrow records: " + e.getMessage());
        }
    }

    private void ensureJsonFileExists() {
        File jsonFile = new File(FILE_NAME);
        if (jsonFile.exists()) {
            return;
        }

        borrowRecords = new ArrayList<>();
        saveBorrowRecords();
    }

    private String escapeJson(String value) {
        return value.replace("\\", "\\\\")
                .replace("\"", "\\\"")
                .replace("\n", "\\n")
                .replace("\r", "\\r")
                .replace("\t", "\\t");
    }

    private String unescapeJson(String value) {
        return value.replace("\\\"", "\"")
                .replace("\\n", "\n")
                .replace("\\r", "\r")
                .replace("\\t", "\t")
                .replace("\\\\", "\\");
    }

    private String extractString(String obj, String key) {
        Pattern p = Pattern.compile("\"" + key + "\"\\s*:\\s*\"((?:\\\\.|[^\"\\\\])*)\"");
        Matcher m = p.matcher(obj);
        if (!m.find()) {
            return null;
        }
        return unescapeJson(m.group(1));
    }
}

import java.io.*;
import java.util.ArrayList;
import java.util.InputMismatchException;
import java.util.Scanner;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class BookManagement {

    private ArrayList<Book> bookList = new ArrayList<>();
    private final Scanner scanner;

    private static final String FILE_NAME = "books.json";

    public BookManagement(Scanner scanner) {
        this.scanner = scanner;
    }

    //  MAIN RUN METHOD
    public void run() {
        loadBooks();

        while (true) {
            try {
                System.out.println("\n--- Book Management ---");
                System.out.println("1. Add Book");
                System.out.println("2. Update Book");
                System.out.println("3. Delete Book");
                System.out.println("4. Search Book");
                System.out.println("5. View All Books");
                System.out.println("6. Exit");
                System.out.print("Enter choice: ");

                int action = scanner.nextInt();
                scanner.nextLine();

                switch (action) {
                    case 1 -> addBook();
                    case 2 -> updateBook();
                    case 3 -> deleteBook();
                    case 4 -> searchBooks();
                    case 5 -> viewBooks();
                    case 6 -> {
                        saveBooks();
                        System.out.println("Exiting...");
                        return;
                    }
                    default -> System.out.println("Invalid option.");
                }

            } catch (InputMismatchException e) {
                System.out.println("Invalid input. Please enter a number.");
                scanner.nextLine();
            } catch (Exception e) {
                System.out.println("Unexpected error: " + e.getMessage());
            }
        }
    }

    //  ADD
    private void addBook() {
    try {
        System.out.print("Enter Title: ");
        String title = scanner.nextLine();
        System.out.print("Enter Author: ");
        String author = scanner.nextLine();
        System.out.print("Enter Year: ");
        int year = scanner.nextInt();
        scanner.nextLine(); // Clear buffer
        System.out.print("Enter Genre: ");
        String genre = scanner.nextLine();
        System.out.print("Enter ISBN: ");
        String isbn = scanner.nextLine();

        bookList.add(new Book(title, author, year, genre, isbn));
        saveBooks();
        System.out.println("Book added successfully!");
    } catch (Exception e) {
        System.out.println("Error: Could not add book. Check your input.");
        scanner.nextLine(); // Clear buffer in case of error
    }
}

    //  UPDATE
    private void updateBook() {
        try {
            System.out.print("Select book number: ");
            int index = scanner.nextInt() - 1;
            scanner.nextLine();

            if (index < 0 || index >= bookList.size()) {
                System.out.println("Invalid selection.");
                return;
            }

            System.out.print("Enter new title: ");
            String newTitle = scanner.nextLine().trim();

            if (newTitle.isEmpty()) {
                System.out.println("Title cannot be empty.");
                return;
            }

            bookList.get(index).setTitle(newTitle);
            saveBooks();
            System.out.println("Book updated.");

        } catch (InputMismatchException e) {
            System.out.println("Please enter a valid number.");
            scanner.nextLine();
        } catch (Exception e) {
            System.out.println("Error updating book.");
        }
    }

    //  DELETE (FIXED)
    private void deleteBook() {
        try {
            viewBooks();
            if (bookList.isEmpty()) return;

            System.out.print("Select book number: ");
            int index = scanner.nextInt() - 1;
            scanner.nextLine();

            if (index < 0 || index >= bookList.size()) {
                System.out.println("Invalid selection.");
                return;
            }

            Book removed = bookList.remove(index);
            saveBooks();
            System.out.println("Deleted: " + removed);

        } catch (InputMismatchException e) {
            System.out.println("Please enter a valid number.");
            scanner.nextLine();
        } catch (Exception e) {
            System.out.println("Error deleting book.");
        }
    }

     //  SEARCH
     private void searchBooks() {
         try {
             System.out.println("\n--- Search Book ---");
             System.out.println("1. Search by Title");
             System.out.println("2. Search by Author");
             System.out.println("3. Search by Year");
             System.out.println("4. Search by Genre");
             System.out.println("5. Search by ISBN");
             System.out.print("Enter choice: ");

             int searchChoice = scanner.nextInt();
             scanner.nextLine();

             ArrayList<Book> results = new ArrayList<>();

             switch (searchChoice) {
                 case 1 -> {
                     System.out.print("Enter title to search: ");
                     String title = scanner.nextLine().trim();
                     for (Book b : bookList) {
                         if (b.getTitle().equalsIgnoreCase(title)) {
                             results.add(b);
                         }
                     }
                 }
                 case 2 -> {
                     System.out.print("Enter author to search: ");
                     String author = scanner.nextLine().trim();
                     for (Book b : bookList) {
                         if (b.getAuthor().equalsIgnoreCase(author)) {
                             results.add(b);
                         }
                     }
                 }
                 case 3 -> {
                     System.out.print("Enter year to search: ");
                     int year = scanner.nextInt();
                     scanner.nextLine();
                     for (Book b : bookList) {
                         if (b.getYear() == year) {
                             results.add(b);
                         }
                     }
                 }
                 case 4 -> {
                     System.out.print("Enter genre to search: ");
                     String genre = scanner.nextLine().trim();
                     for (Book b : bookList) {
                         if (b.getGenre().equalsIgnoreCase(genre)) {
                             results.add(b);
                         }
                     }
                 }
                 case 5 -> {
                     System.out.print("Enter ISBN to search: ");
                     String isbn = scanner.nextLine().trim();
                     for (Book b : bookList) {
                         if (b.getIsbn().equalsIgnoreCase(isbn)) {
                             results.add(b);
                         }
                     }
                 }
                 default -> System.out.println("Invalid choice.");
             }

             if (results.isEmpty()) {
                 System.out.println("No books found.");
             } else {
                 System.out.println("\n===== Search Results =====");
                 for (int i = 0; i < results.size(); i++) {
                     System.out.println((i + 1) + ". " + results.get(i));
                 }
             }

         } catch (InputMismatchException e) {
             System.out.println("Invalid input. Please enter valid data.");
             scanner.nextLine();
         } catch (Exception e) {
             System.out.println("Error searching books.");
         }
     }

    //  VIEW
    private void viewBooks() {
        System.out.println("\n===== Book List =====");

        if (bookList.isEmpty()) {
            System.out.println("No books available.");
            return;
        }

        for (int i = 0; i < bookList.size(); i++) {
            System.out.println((i + 1) + ". " + bookList.get(i));
        }
    }

    // SAVE JSON
    private void saveBooks() {
        try (BufferedWriter writer = new BufferedWriter(new FileWriter(FILE_NAME))) {
            writer.write("[\n");
            for (int i = 0; i < bookList.size(); i++) {
                Book book = bookList.get(i);
                writer.write("  {\n");
                writer.write("    \"title\": \"" + escapeJson(book.getTitle()) + "\",\n");
                writer.write("    \"author\": \"" + escapeJson(book.getAuthor()) + "\",\n");
                writer.write("    \"year\": " + book.getYear() + ",\n");
                writer.write("    \"genre\": \"" + escapeJson(book.getGenre()) + "\",\n");
                writer.write("    \"isbn\": \"" + escapeJson(book.getIsbn()) + "\"\n");
                writer.write("  }");
                if (i < bookList.size() - 1) {
                    writer.write(",");
                }
                writer.newLine();
            }
            writer.write("]");
        } catch (IOException e) {
            System.out.println("Error saving file: " + e.getMessage());
        }
    }

    // LOAD JSON
    private void loadBooks() {
        ensureJsonFileExists();
        bookList = new ArrayList<>();
        try (BufferedReader reader = new BufferedReader(new FileReader(FILE_NAME))) {
            StringBuilder json = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) {
                json.append(line).append('\n');
            }

            Pattern objectPattern = Pattern.compile("\\{[^{}]*}");
            Matcher objectMatcher = objectPattern.matcher(json.toString());

            while (objectMatcher.find()) {
                String obj = objectMatcher.group();
                String title = extractString(obj, "title");
                String author = extractString(obj, "author");
                Integer year = extractInt(obj, "year");
                String genre = extractString(obj, "genre");
                String isbn = extractString(obj, "isbn");

                if (title == null || author == null || year == null || genre == null || isbn == null) {
                    continue;
                }

                bookList.add(new Book(title, author, year, genre, isbn));
            }
        } catch (IOException e) {
            System.out.println("Error loading file: " + e.getMessage());
        }
    }

    private void ensureJsonFileExists() {
        File jsonFile = new File(FILE_NAME);
        if (jsonFile.exists()) {
            return;
        }

        bookList = new ArrayList<>();
        saveBooks();
    }

    private String escapeJson(String value) {
        return value.replace("\\", "\\\\")
                .replace("\"", "\\\"")
                .replace("\n", "\\n")
                .replace("\r", "\\r")
                .replace("\t", "\\t");
    }

    private String unescapeJson(String value) {
        return value.replace("\\\"", "\"")
                .replace("\\n", "\n")
                .replace("\\r", "\r")
                .replace("\\t", "\t")
                .replace("\\\\", "\\");
    }

    private String extractString(String obj, String key) {
        Pattern p = Pattern.compile("\"" + key + "\"\\s*:\\s*\"((?:\\\\.|[^\"\\\\])*)\"");
        Matcher m = p.matcher(obj);
        if (!m.find()) {
            return null;
        }
        return unescapeJson(m.group(1));
    }

    private Integer extractInt(String obj, String key) {
        Pattern p = Pattern.compile("\"" + key + "\"\\s*:\\s*(-?\\d+)");
        Matcher m = p.matcher(obj);
        if (!m.find()) {
            return null;
        }
        try {
            return Integer.parseInt(m.group(1));
        } catch (NumberFormatException e) {
            return null;
        }
    }

    //  PUBLIC METHOD TO LOAD BOOKS (for external use)
    public void loadBooksData() {
        loadBooks();
    }
}

import java.io.*;
import java.util.ArrayList;
import java.util.InputMismatchException;
import java.util.Scanner;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class BookManagement {

    private ArrayList<Book> bookList = new ArrayList<>();
    private final Scanner scanner;

    private static final String FILE_NAME = "books.json";

    public BookManagement(Scanner scanner) {
        this.scanner = scanner;
    }

    //  MAIN RUN METHOD
    public void run() {
        loadBooks();

        while (true) {
            try {
                System.out.println("\n--- Book Management ---");
                System.out.println("1. Add Book");
                System.out.println("2. Update Book");
                System.out.println("3. Delete Book");
                System.out.println("4. Search Book");
                System.out.println("5. View All Books");
                System.out.println("6. Exit");
                System.out.print("Enter choice: ");

                int action = scanner.nextInt();
                scanner.nextLine();

                switch (action) {
                    case 1 -> addBook();
                    case 2 -> updateBook();
                    case 3 -> deleteBook();
                    case 4 -> searchBooks();
                    case 5 -> viewBooks();
                    case 6 -> {
                        saveBooks();
                        System.out.println("Exiting...");
                        return;
                    }
                    default -> System.out.println("Invalid option.");
                }

            } catch (InputMismatchException e) {
                System.out.println("Invalid input. Please enter a number.");
                scanner.nextLine();
            } catch (Exception e) {
                System.out.println("Unexpected error: " + e.getMessage());
            }
        }
    }

    //  ADD
    private void addBook() {
    try {
        System.out.print("Enter Title: ");
        String title = scanner.nextLine();
        System.out.print("Enter Author: ");
        String author = scanner.nextLine();
        System.out.print("Enter Year: ");
        int year = scanner.nextInt();
        scanner.nextLine(); // Clear buffer
        System.out.print("Enter Genre: ");
        String genre = scanner.nextLine();
        System.out.print("Enter ISBN: ");
        String isbn = scanner.nextLine();

        bookList.add(new Book(title, author, year, genre, isbn));
        saveBooks();
        System.out.println("Book added successfully!");
    } catch (Exception e) {
        System.out.println("Error: Could not add book. Check your input.");
        scanner.nextLine(); // Clear buffer in case of error
    }
}

    //  UPDATE
    private void updateBook() {
        try {
            System.out.print("Select book number: ");
            int index = scanner.nextInt() - 1;
            scanner.nextLine();

            if (index < 0 || index >= bookList.size()) {
                System.out.println("Invalid selection.");
                return;
            }

            System.out.print("Enter new title: ");
            String newTitle = scanner.nextLine().trim();

            if (newTitle.isEmpty()) {
                System.out.println("Title cannot be empty.");
                return;
            }

            bookList.get(index).setTitle(newTitle);
            saveBooks();
            System.out.println("Book updated.");

        } catch (InputMismatchException e) {
            System.out.println("Please enter a valid number.");
            scanner.nextLine();
        } catch (Exception e) {
            System.out.println("Error updating book.");
        }
    }

    //  DELETE (FIXED)
    private void deleteBook() {
        try {
            viewBooks();
            if (bookList.isEmpty()) return;

            System.out.print("Select book number: ");
            int index = scanner.nextInt() - 1;
            scanner.nextLine();

            if (index < 0 || index >= bookList.size()) {
                System.out.println("Invalid selection.");
                return;
            }

            Book removed = bookList.remove(index);
            saveBooks();
            System.out.println("Deleted: " + removed);

        } catch (InputMismatchException e) {
            System.out.println("Please enter a valid number.");
            scanner.nextLine();
        } catch (Exception e) {
            System.out.println("Error deleting book.");
        }
    }

     //  SEARCH
     private void searchBooks() {
         try {
             System.out.println("\n--- Search Book ---");
             System.out.println("1. Search by Title");
             System.out.println("2. Search by Author");
             System.out.println("3. Search by Year");
             System.out.println("4. Search by Genre");
             System.out.println("5. Search by ISBN");
             System.out.print("Enter choice: ");

             int searchChoice = scanner.nextInt();
             scanner.nextLine();

             ArrayList<Book> results = new ArrayList<>();

             switch (searchChoice) {
                 case 1 -> {
                     System.out.print("Enter title to search: ");
                     String title = scanner.nextLine().trim();
                     for (Book b : bookList) {
                         if (b.getTitle().equalsIgnoreCase(title)) {
                             results.add(b);
                         }
                     }
                 }
                 case 2 -> {
                     System.out.print("Enter author to search: ");
                     String author = scanner.nextLine().trim();
                     for (Book b : bookList) {
                         if (b.getAuthor().equalsIgnoreCase(author)) {
                             results.add(b);
                         }
                     }
                 }
                 case 3 -> {
                     System.out.print("Enter year to search: ");
                     int year = scanner.nextInt();
                     scanner.nextLine();
                     for (Book b : bookList) {
                         if (b.getYear() == year) {
                             results.add(b);
                         }
                     }
                 }
                 case 4 -> {
                     System.out.print("Enter genre to search: ");
                     String genre = scanner.nextLine().trim();
                     for (Book b : bookList) {
                         if (b.getGenre().equalsIgnoreCase(genre)) {
                             results.add(b);
                         }
                     }
                 }
                 case 5 -> {
                     System.out.print("Enter ISBN to search: ");
                     String isbn = scanner.nextLine().trim();
                     for (Book b : bookList) {
                         if (b.getIsbn().equalsIgnoreCase(isbn)) {
                             results.add(b);
                         }
                     }
                 }
                 default -> System.out.println("Invalid choice.");
             }

             if (results.isEmpty()) {
                 System.out.println("No books found.");
             } else {
                 System.out.println("\n===== Search Results =====");
                 for (int i = 0; i < results.size(); i++) {
                     System.out.println((i + 1) + ". " + results.get(i));
                 }
             }

         } catch (InputMismatchException e) {
             System.out.println("Invalid input. Please enter valid data.");
             scanner.nextLine();
         } catch (Exception e) {
             System.out.println("Error searching books.");
         }
     }

    //  VIEW
    private void viewBooks() {
        System.out.println("\n===== Book List =====");

        if (bookList.isEmpty()) {
            System.out.println("No books available.");
            return;
        }

        for (int i = 0; i < bookList.size(); i++) {
            System.out.println((i + 1) + ". " + bookList.get(i));
        }
    }

    // SAVE JSON
    private void saveBooks() {
        try (BufferedWriter writer = new BufferedWriter(new FileWriter(FILE_NAME))) {
            writer.write("[\n");
            for (int i = 0; i < bookList.size(); i++) {
                Book book = bookList.get(i);
                writer.write("  {\n");
                writer.write("    \"title\": \"" + escapeJson(book.getTitle()) + "\",\n");
                writer.write("    \"author\": \"" + escapeJson(book.getAuthor()) + "\",\n");
                writer.write("    \"year\": " + book.getYear() + ",\n");
                writer.write("    \"genre\": \"" + escapeJson(book.getGenre()) + "\",\n");
                writer.write("    \"isbn\": \"" + escapeJson(book.getIsbn()) + "\"\n");
                writer.write("  }");
                if (i < bookList.size() - 1) {
                    writer.write(",");
                }
                writer.newLine();
            }
            writer.write("]");
        } catch (IOException e) {
            System.out.println("Error saving file: " + e.getMessage());
        }
    }

    // LOAD JSON
    private void loadBooks() {
        ensureJsonFileExists();
        bookList = new ArrayList<>();
        try (BufferedReader reader = new BufferedReader(new FileReader(FILE_NAME))) {
            StringBuilder json = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) {
                json.append(line).append('\n');
            }

            Pattern objectPattern = Pattern.compile("\\{[^{}]*}");
            Matcher objectMatcher = objectPattern.matcher(json.toString());

            while (objectMatcher.find()) {
                String obj = objectMatcher.group();
                String title = extractString(obj, "title");
                String author = extractString(obj, "author");
                Integer year = extractInt(obj, "year");
                String genre = extractString(obj, "genre");
                String isbn = extractString(obj, "isbn");

                if (title == null || author == null || year == null || genre == null || isbn == null) {
                    continue;
                }

                bookList.add(new Book(title, author, year, genre, isbn));
            }
        } catch (IOException e) {
            System.out.println("Error loading file: " + e.getMessage());
        }
    }

    private void ensureJsonFileExists() {
        File jsonFile = new File(FILE_NAME);
        if (jsonFile.exists()) {
            return;
        }

        bookList = new ArrayList<>();
        saveBooks();
    }

    private String escapeJson(String value) {
        return value.replace("\\", "\\\\")
                .replace("\"", "\\\"")
                .replace("\n", "\\n")
                .replace("\r", "\\r")
                .replace("\t", "\\t");
    }

    private String unescapeJson(String value) {
        return value.replace("\\\"", "\"")
                .replace("\\n", "\n")
                .replace("\\r", "\r")
                .replace("\\t", "\t")
                .replace("\\\\", "\\");
    }

    private String extractString(String obj, String key) {
        Pattern p = Pattern.compile("\"" + key + "\"\\s*:\\s*\"((?:\\\\.|[^\"\\\\])*)\"");
        Matcher m = p.matcher(obj);
        if (!m.find()) {
            return null;
        }
        return unescapeJson(m.group(1));
    }

    private Integer extractInt(String obj, String key) {
        Pattern p = Pattern.compile("\"" + key + "\"\\s*:\\s*(-?\\d+)");
        Matcher m = p.matcher(obj);
        if (!m.find()) {
            return null;
        }
        try {
            return Integer.parseInt(m.group(1));
        } catch (NumberFormatException e) {
            return null;
        }
    }

    //  PUBLIC METHOD TO LOAD BOOKS (for external use)
    public void loadBooksData() {
        loadBooks();
    }

    //  PUBLIC GETTER FOR BOOK LIST
    public ArrayList<Book> getBookList() {
        return bookList;
    }
}

