             System.out.print("Enter name: ");
             String name = scanner.nextLine().trim();

             if (name.isEmpty()) {
                 System.out.println("Name cannot be empty.");
                 return;
             }

             String memberId = generateMemberId();
             memberList.add(new Member(memberId, name));
             saveMembers();
             System.out.println("Member added with ID: " + memberId);

         } catch (Exception e) {
             System.out.println("Error adding member.");
         }
     }

    //  UPDATE
    private void updateMember() {
        try {
            System.out.print("Select member number: ");
            int index = scanner.nextInt() - 1;
            scanner.nextLine();

            if (index < 0 || index >= memberList.size()) {
                System.out.println("Invalid selection.");
                return;
            }

            System.out.print("Enter new name: ");
            String newName = scanner.nextLine().trim();

            if (newName.isEmpty()) {
                System.out.println("Name cannot be empty.");
                return;
            }

            memberList.get(index).setName(newName);
            saveMembers();
            System.out.println("Member updated.");

        } catch (InputMismatchException e) {
            System.out.println("Please enter a valid number.");
            scanner.nextLine();
        } catch (Exception e) {
            System.out.println("Error updating member.");
        }
    }

    //  DELETE (FIXED)
    private void deleteMember() {
        try {
            viewMembers();
            if (memberList.isEmpty()) return;

            System.out.print("Select member number: ");
            int index = scanner.nextInt() - 1;
            scanner.nextLine();

            if (index < 0 || index >= memberList.size()) {
                System.out.println("Invalid selection.");
                return;
            }

            Member removed = memberList.remove(index);
            saveMembers();
            System.out.println("Deleted: " + removed);

        } catch (InputMismatchException e) {
            System.out.println("Please enter a valid number.");
            scanner.nextLine();
        } catch (Exception e) {
            System.out.println("Error deleting member.");
        }
    }

     //  SEARCH
     private void searchMember() {
         try {
             System.out.println("\nSearch Member By:");
             System.out.println("1. ID");
             System.out.println("2. Name");
             System.out.print("Select option: ");

             int option = scanner.nextInt();
             scanner.nextLine();

             switch (option) {
                 case 1 -> searchById();
                 case 2 -> searchByName();
                 default -> System.out.println("Invalid option.");
             }

         } catch (InputMismatchException e) {
             System.out.println("Please enter a valid number.");
             scanner.nextLine();
         } catch (Exception e) {
             System.out.println("Error searching member.");
         }
     }

     //  SEARCH BY ID
     private void searchById() {
         try {
             System.out.print("Enter member ID to search: ");
             String id = scanner.nextLine().trim();

             ArrayList<Member> results = new ArrayList<>();
             for (Member m : memberList) {
                 if (m.getId().equalsIgnoreCase(id)) {
                     results.add(m);
                 }
             }

             if (results.isEmpty()) {
                 System.out.println("Member not found.");
             } else {
                 System.out.println("\nSearch Results:");
                 for (Member m : results) {
                     System.out.println(m);
                 }
             }

         } catch (Exception e) {
             System.out.println("Error searching member by ID.");
         }
     }

     //  SEARCH BY NAME
     private void searchByName() {
         try {
             System.out.print("Enter name to search: ");
             String name = scanner.nextLine().trim();

             ArrayList<Member> results = new ArrayList<>();
             for (Member m : memberList) {
                 if (m.getName().equalsIgnoreCase(name)) {
                     results.add(m);
                 }
             }

             if (results.isEmpty()) {
                 System.out.println("Member not found.");
             } else {
                 System.out.println("\nSearch Results:");
                 for (Member m : results) {
                     System.out.println(m);
                 }
             }

         } catch (Exception e) {
             System.out.println("Error searching member by name.");
         }
     }

    //  VIEW
    private void viewMembers() {
        System.out.println("\n===== Member List =====");

        if (memberList.isEmpty()) {
            System.out.println("No members available.");
            return;
        }

        for (int i = 0; i < memberList.size(); i++) {
            System.out.println((i + 1) + ". " + memberList.get(i));
        }
    }

     // SAVE JSON
     private void saveMembers() {
         try (BufferedWriter writer = new BufferedWriter(new FileWriter(FILE_NAME))) {
             writer.write("[\n");
             for (int i = 0; i < memberList.size(); i++) {
                 Member member = memberList.get(i);
                 writer.write("  {\n");
                 writer.write("    \"id\": \"" + escapeJson(member.getId()) + "\",\n");
                 writer.write("    \"name\": \"" + escapeJson(member.getName()) + "\"\n");
                 writer.write("  }");
                 if (i < memberList.size() - 1) {
                     writer.write(",");
                 }
                 writer.newLine();
             }
             writer.write("]");
         } catch (IOException e) {
             System.out.println("Error saving file: " + e.getMessage());
         }
     }

     // LOAD JSON
     private void loadMembers() {
         ensureJsonFileExists();
         memberList = new ArrayList<>();
         try (BufferedReader reader = new BufferedReader(new FileReader(FILE_NAME))) {
             StringBuilder json = new StringBuilder();
             String line;
             while ((line = reader.readLine()) != null) {
                 json.append(line).append('\n');
             }

             Pattern objectPattern = Pattern.compile("\\{[^{}]*}");
             Matcher objectMatcher = objectPattern.matcher(json.toString());

             while (objectMatcher.find()) {
                 String obj = objectMatcher.group();
                 String id = extractString(obj, "id");
                 String name = extractString(obj, "name");
                 if (name == null || name.trim().isEmpty()) {
                     continue;
                 }
                 if (id == null) {
                     id = generateMemberId();
                 }
                 memberList.add(new Member(id, name));
             }
         } catch (IOException e) {
             System.out.println("Error loading file: " + e.getMessage());
         }
     }

    private void ensureJsonFileExists() {
        File jsonFile = new File(FILE_NAME);
        if (jsonFile.exists()) {
            return;
        }

        memberList = new ArrayList<>();
        saveMembers();
    }

    private String escapeJson(String value) {
        return value.replace("\\", "\\\\")
                .replace("\"", "\\\"")
                .replace("\n", "\\n")
                .replace("\r", "\\r")
                .replace("\t", "\\t");
    }

    private String unescapeJson(String value) {
        return value.replace("\\\"", "\"")
                .replace("\\n", "\n")
                .replace("\\r", "\r")
                .replace("\\t", "\t")
                .replace("\\\\", "\\");
    }

    private String extractString(String obj, String key) {
        Pattern p = Pattern.compile("\"" + key + "\"\\s*:\\s*\"((?:\\\\.|[^\"\\\\])*)\"");
        Matcher m = p.matcher(obj);
        if (!m.find()) {
            return null;
        }
        return unescapeJson(m.group(1));
    }

    private String generateMemberId() {
        int nextId = memberList.size() + 1;
        return String.format("%03d", nextId);
    }

    //  PUBLIC METHOD TO LOAD MEMBERS (for external use)
    public void loadMembersData() {
        loadMembers();
    }
}

